USE HanoiBusDB;
GO

-- NÂNG CẤP CẤU TRÚC CỘT HỖ TRỢ TIẾNG VIỆT VÀ ĐỘ DÀI MÔ TẢ
ALTER TABLE Routes ALTER COLUMN OperatingHours NVARCHAR(150) NOT NULL;
ALTER TABLE Routes ALTER COLUMN Frequency NVARCHAR(150);
GO

-- XÓA DỮ LIỆU CŨ TRƯỚC KHI CHÈN (đúng thứ tự để không vi phạm khóa ngoại)
DELETE FROM BusLocationHistory;
