GO

-- RESEED IDENTITY VỀ 0 CHO CÁC BẢNG CHÈN DỮ LIỆU KHÔNG DÙNG IDENTITY_INSERT
-- (đảm bảo ID tự sinh khớp với các ID được tham chiếu "cứng" ở các INSERT bên dưới)
DBCC CHECKIDENT ('Buses', RESEED, 0);
DBCC CHECKIDENT ('Trips', RESEED, 0);
DBCC CHECKIDENT ('Attendance', RESEED, 0);
DBCC CHECKIDENT ('Tickets', RESEED, 0);
DBCC CHECKIDENT ('MonthlyPasses', RESEED, 0);
DBCC CHECKIDENT ('Payments', RESEED, 0);
DBCC CHECKIDENT ('Discounts', RESEED, 0);
DBCC CHECKIDENT ('Notifications', RESEED, 0);
DBCC CHECKIDENT ('NotificationReads', RESEED, 0);
DBCC CHECKIDENT ('BusLocationHistory', RESEED, 0);
DBCC CHECKIDENT ('TripProgress', RESEED, 0);
DBCC CHECKIDENT ('SearchHistory', RESEED, 0);
DBCC CHECKIDENT ('Route_Stop', RESEED, 0);
GO

